import{_ as i,c as r,o as a,ah as n}from"./chunks/framework.Cnj7lwEt.js";const p=JSON.parse('{"title":"🚀 部署工具","description":"","frontmatter":{},"headers":[],"relativePath":"github汇总/部署工具/index.md","filePath":"github汇总/部署工具/index.md"}'),e={name:"github汇总/部署工具/index.md"};function t(o,l,s,h,g,c){return a(),r("div",null,l[0]||(l[0]=[n('<h1 id="🚀-部署工具" tabindex="-1">🚀 部署工具 <a class="header-anchor" href="#🚀-部署工具" aria-label="Permalink to “🚀 部署工具”">​</a></h1><h2 id="概述" tabindex="-1">概述 <a class="header-anchor" href="#概述" aria-label="Permalink to “概述”">​</a></h2><p>部署工具是应用程序部署和运维的重要组成部分。本分类汇集了各类优质的开源部署工具，涵盖 PaaS 平台、API 网关、路由器固件、安装辅助工具等，帮助您简化部署流程，提升运维效率。</p><h2 id="工具列表" tabindex="-1">工具列表 <a class="header-anchor" href="#工具列表" aria-label="Permalink to “工具列表”">​</a></h2><h3 id="coolify" tabindex="-1">Coolify <a class="header-anchor" href="#coolify" aria-label="Permalink to “Coolify”">​</a></h3><ul><li><strong>项目名称</strong>: Coolify</li><li><strong>作者</strong>: coolify-org</li><li><strong>核心功能</strong>: 开源自托管 PaaS 平台，支持多种应用类型部署，免费 SSL 证书自动配置，多种常用数据库一键部署，反向代理支持</li><li><strong>主要亮点</strong>: <ul><li>完全免费开源，MIT 协议</li><li>GitHub 星标超过 2.1 万</li><li>可完美替代 Heroku 和 Netlify</li><li>无需复杂配置，新手也能轻松使用</li><li>自托管，完全掌控部署过程</li></ul></li><li><strong>详细介绍</strong>: <a href="/github汇总/部署工具/Coolify-部署工具.html">Coolify 完整文档</a></li><li><strong>GitHub 地址</strong>: <a href="https://github.com/coolify-org/coolify" target="_blank" rel="noreferrer">https://github.com/coolify-org/coolify</a></li></ul><hr><h3 id="higress" tabindex="-1">higress <a class="header-anchor" href="#higress" aria-label="Permalink to “higress”">​</a></h3><ul><li><strong>项目名称</strong>: higress</li><li><strong>作者</strong>: 阿里云（Alibaba）</li><li><strong>核心功能</strong>: 阿里云开源的云原生网关，基于 Istio 和 Envoy 构建，提供强大的 API 网关和微服务网关能力</li><li><strong>主要亮点</strong>: <ul><li>由阿里云开源</li><li>基于 Istio 和 Envoy 构建</li><li>提供强大的 API 网关和微服务网关能力</li><li>是云原生架构中的重要组件</li><li>采用 Apache-2.0 许可证</li><li>已获得超过 1.4k 星标</li><li>是构建云原生应用架构的核心基础设施</li></ul></li><li><strong>详细介绍</strong>: <a href="/github汇总/部署工具/higress-部署工具.html">higress 完整文档</a></li><li><strong>GitHub 地址</strong>: <a href="https://github.com/alibaba/higress" target="_blank" rel="noreferrer">https://github.com/alibaba/higress</a></li></ul><hr><h3 id="lede" tabindex="-1">lede <a class="header-anchor" href="#lede" aria-label="Permalink to “lede”">​</a></h3><ul><li><strong>项目名称</strong>: lede</li><li><strong>作者</strong>: coolsnowwolf</li><li><strong>核心功能</strong>: Lean&#39;s OpenWrt 源码仓库，提供 OpenWrt 路由器固件源码，支持多种路由器设备</li><li><strong>主要亮点</strong>: <ul><li>Lean&#39;s OpenWrt 源码仓库</li><li>提供 OpenWrt 路由器固件源码</li><li>支持多种路由器设备</li><li>让你可以自定义编译和安装路由器固件</li><li>是路由器爱好者和极客们的必备项目</li><li>采用 GPL-2.0 许可证</li><li>代码活跃更新</li><li>GitHub 上已获得超过 1.4k 星标</li></ul></li><li><strong>详细介绍</strong>: <a href="/github汇总/部署工具/lede-部署工具.html">lede 完整文档</a></li><li><strong>GitHub 地址</strong>: <a href="https://github.com/coolsnowwolf/lede" target="_blank" rel="noreferrer">https://github.com/coolsnowwolf/lede</a></li></ul><hr><h3 id="openclaw-uninstaller" tabindex="-1">openclaw-uninstaller <a class="header-anchor" href="#openclaw-uninstaller" aria-label="Permalink to “openclaw-uninstaller”">​</a></h3><ul><li><strong>项目名称</strong>: openclaw-uninstaller</li><li><strong>作者</strong>: inclusionAI</li><li><strong>核心功能</strong>: OpenClaw 卸载工具，用于完全移除 OpenClaw 相关组件</li><li><strong>主要亮点</strong>: <ul><li>OpenClaw 卸载工具</li><li>用于完全移除 OpenClaw 相关组件</li><li>由 inclusionAI 社区开发</li></ul></li><li><strong>详细介绍</strong>: <a href="/github汇总/部署工具/openclaw-uninstaller-部署工具.html">openclaw-uninstaller 完整文档</a></li><li><strong>GitHub 地址</strong>: <a href="https://github.com/inclusionAI/openclaw-uninstaller" target="_blank" rel="noreferrer">https://github.com/inclusionAI/openclaw-uninstaller</a></li></ul><hr><h3 id="openclawinstaller" tabindex="-1">OpenClawInstaller <a class="header-anchor" href="#openclawinstaller" aria-label="Permalink to “OpenClawInstaller”">​</a></h3><ul><li><strong>项目名称</strong>: OpenClawInstaller</li><li><strong>作者</strong>: inclusionAI</li><li><strong>核心功能</strong>: OpenClaw 一键安装工具，简化 OpenClaw 安装流程，让安装过程更简单便捷，支持 Windows、Linux、MacOS 多操作系统</li><li><strong>主要亮点</strong>: <ul><li>一键安装，操作简单</li><li>支持多操作系统</li><li>简化复杂的安装流程</li><li>由 inclusionAI 社区开发</li><li>让更多人能够轻松上手 OpenClaw</li></ul></li><li><strong>详细介绍</strong>: <a href="/github汇总/部署工具/OpenClawInstaller-部署工具.html">OpenClawInstaller 完整文档</a></li><li><strong>GitHub 地址</strong>: <a href="https://github.com/inclusionAI/OpenClawInstaller" target="_blank" rel="noreferrer">https://github.com/inclusionAI/OpenClawInstaller</a></li></ul><h2 id="分类特点" tabindex="-1">分类特点 <a class="header-anchor" href="#分类特点" aria-label="Permalink to “分类特点”">​</a></h2><p>本分类部署工具涵盖以下类型：</p><ul><li><strong>PaaS 平台</strong> - Coolify</li><li><strong>API 网关</strong> - higress</li><li><strong>路由器固件</strong> - lede</li><li><strong>安装辅助工具</strong> - OpenClawInstaller、openclaw-uninstaller</li></ul><h2 id="工具选择建议" tabindex="-1">工具选择建议 <a class="header-anchor" href="#工具选择建议" aria-label="Permalink to “工具选择建议”">​</a></h2><ol><li><strong>应用部署</strong> - 推荐使用 Coolify</li><li><strong>云原生网关</strong> - 推荐使用 higress</li><li><strong>路由器定制</strong> - 推荐使用 lede</li><li><strong>OpenClaw 管理</strong> - 推荐使用 OpenClawInstaller 和 openclaw-uninstaller</li></ol><h2 id="贡献建议" tabindex="-1">贡献建议 <a class="header-anchor" href="#贡献建议" aria-label="Permalink to “贡献建议”">​</a></h2><p>如果您发现了优质的部署工具想要分享，欢迎通过以下方式贡献：</p><ul><li>提交 Issue 推荐项目</li><li>提交 PR 添加新资源</li></ul><hr><p><em>开始探索，发现更多部署工具！</em> 🚀</p>',28)]))}const d=i(e,[["render",t]]);export{p as __pageData,d as default};
